import re
from datetime import datetime, date

WEIGHTS = {
    "recency": 0.30,
    "seniority": 0.25,
    "shared_connections": 0.25,
    "source_diversity": 0.20,
}

_CSUITE_RE = re.compile(
    r"\b(ceo|cfo|coo|cto|cio|cmo|chief|partner|managing director|md)\b", re.I
)
_VP_RE = re.compile(r"\b(vp|vice president|director|head of)\b", re.I)
_MGR_RE = re.compile(r"\b(manager|senior|sr\.?|lead)\b", re.I)


def recency_score(connected_on: date | None) -> float:
    if connected_on is None:
        return 0.3
    days = (datetime.now().date() - connected_on).days
    if days <= 365:
        return 1.0
    if days <= 365 * 3:
        return 0.6
    return 0.3


def seniority_score(title: str | None) -> float:
    if not title:
        return 0.2
    if _CSUITE_RE.search(title):
        return 1.0
    if _VP_RE.search(title):
        return 0.7
    if _MGR_RE.search(title):
        return 0.4
    return 0.2


def shared_connections_score(count: int) -> float:
    if count >= 3:
        return 1.0
    if count == 2:
        return 0.6
    return 0.2


def source_diversity_score(source_count: int) -> float:
    return 1.0 if source_count > 1 else 0.0


def compute_strength(
    connected_on: date | None,
    title: str | None,
    shared_count: int,
    source_count: int,
) -> float:
    return round(
        recency_score(connected_on) * WEIGHTS["recency"]
        + seniority_score(title) * WEIGHTS["seniority"]
        + shared_connections_score(shared_count) * WEIGHTS["shared_connections"]
        + source_diversity_score(source_count) * WEIGHTS["source_diversity"],
        3,
    )


def score_breakdown(
    connected_on: date | None,
    title: str | None,
    shared_count: int,
    source_count: int,
) -> dict:
    return {
        "overall": compute_strength(connected_on, title, shared_count, source_count),
        "recency": recency_score(connected_on),
        "seniority": seniority_score(title),
        "shared_connections": shared_count,
        "source_diversity": source_count > 1,
    }

from fastapi import APIRouter, Depends, HTTPException

from backend.routers.auth import verify_api_key
from backend.services.graph_service import (
    find_shortest_path,
    get_full_graph,
    get_score_details,
    search_graph,
)

router = APIRouter(prefix="/api/graph", tags=["graph"])


@router.get("/path")
async def graph_path(
    source_member: str,
    target_name: str,
    target_company: str | None = None,
    _key: str = Depends(verify_api_key),
):
    path = await find_shortest_path(source_member, target_name, target_company)
    if not path:
        raise HTTPException(status_code=404, detail="No path found")
    return {"path": path}


@router.get("/search")
async def graph_search(
    company: str | None = None,
    role: str | None = None,
    _key: str = Depends(verify_api_key),
):
    results = await search_graph(company, role)
    return {"results": results}


@router.get("/score")
async def graph_score(
    person_id: str,
    _key: str = Depends(verify_api_key),
):
    details = await get_score_details(person_id)
    if not details:
        raise HTTPException(status_code=404, detail="Person not found")
    return details


@router.get("/all")
async def graph_all(_key: str = Depends(verify_api_key)):
    return await get_full_graph()

import json
import logging
import os
import re

from fastapi import APIRouter, Depends
from pydantic import BaseModel

from backend.routers.auth import verify_api_key
from backend.services.graph_service import (
    find_shortest_path,
    get_score_details,
    search_graph,
)

logger = logging.getLogger(__name__)

router = APIRouter(prefix="/api", tags=["chat"])

TOOL_DEFINITIONS = [
    {
        "type": "function",
        "function": {
            "name": "find_warm_path",
            "description": "Find the shortest warm introduction path from a TSI team member to a target person or company contact.",
            "parameters": {
                "type": "object",
                "properties": {
                    "source_member": {
                        "type": "string",
                        "description": "Full name of the TSI team member who is the starting point",
                    },
                    "target_name": {
                        "type": "string",
                        "description": "Name or role of the target person to reach",
                    },
                    "target_company": {
                        "type": "string",
                        "description": "Company the target works at",
                    },
                },
                "required": ["source_member", "target_name"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "search_by_company_or_role",
            "description": "Search the network for contacts by company name and/or role/title.",
            "parameters": {
                "type": "object",
                "properties": {
                    "company": {
                        "type": "string",
                        "description": "Company name to filter by",
                    },
                    "role": {
                        "type": "string",
                        "description": "Role or title to filter by",
                    },
                },
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "score_relationship_strength",
            "description": "Get detailed relationship strength score breakdown for a specific contact.",
            "parameters": {
                "type": "object",
                "properties": {
                    "person_id": {
                        "type": "string",
                        "description": "The unique person ID (slug) of the contact",
                    },
                },
                "required": ["person_id"],
            },
        },
    },
]

SYSTEM_PROMPT = """You are a relationship intelligence assistant for a capital markets BD team.
You help find warm introduction paths, search the network, and analyze relationship strength.

When the user asks about connections or paths, use the available tools.
When asked "who do we know at X", use search_by_company_or_role.
When asked to find a path or warm intro, use find_warm_path.
When asked about relationship strength, use score_relationship_strength.

Be concise, professional, and format results clearly."""


class ChatMessage(BaseModel):
    role: str
    content: str


class ChatRequest(BaseModel):
    message: str
    history: list[ChatMessage] = []
    source_member: str = ""


async def _execute_tool(name: str, args: dict) -> dict:
    if name == "find_warm_path":
        path = await find_shortest_path(
            args.get("source_member", ""),
            args.get("target_name", ""),
            args.get("target_company"),
        )
        return {"type": "path", "data": path}
    elif name == "search_by_company_or_role":
        results = await search_graph(args.get("company"), args.get("role"))
        return {"type": "search", "data": results}
    elif name == "score_relationship_strength":
        details = await get_score_details(args.get("person_id", ""))
        return {"type": "score", "data": details}
    return {"type": "error", "data": "Unknown tool"}


def _fallback_intent(message: str) -> tuple[str, dict] | None:
    """Regex-based intent parser when no LLM is configured."""
    msg = message.lower()

    path_match = re.search(
        r"(?:path|intro|introduction|connect|reach).*?(?:to|at)\s+(?:the\s+)?(.+?)(?:\s+at\s+)(.+)",
        msg,
    )
    if path_match:
        return "find_warm_path", {
            "target_name": path_match.group(1).strip(),
            "target_company": path_match.group(2).strip().rstrip("?. "),
        }

    company_match = re.search(
        r"(?:who|know|connections?|contacts?|people).*?(?:at|from)\s+(.+)",
        msg,
    )
    if company_match:
        return "search_by_company_or_role", {
            "company": company_match.group(1).strip().rstrip("?. "),
        }

    role_match = re.search(
        r"(?:find|search|show).*?(cio|cto|ceo|cfo|partner|director|vp|md|managing director)",
        msg,
    )
    if role_match:
        return "search_by_company_or_role", {"role": role_match.group(1).strip()}

    return None


@router.post("/chat")
async def chat(
    request: ChatRequest,
    _key: str = Depends(verify_api_key),
):
    api_key = os.environ.get("GEMINI_API_KEY", "")
    base_url = os.environ.get(
        "LLM_BASE_URL",
        "https://generativelanguage.googleapis.com/v1beta/openai/",
    )
    model = os.environ.get("LLM_MODEL", "gemini-2.0-flash")

    # If no LLM key, use fallback intent parser
    if not api_key or api_key == "your_gemini_api_key_here":
        intent = _fallback_intent(request.message)
        if intent:
            tool_name, tool_args = intent
            if tool_name == "find_warm_path" and request.source_member:
                tool_args["source_member"] = request.source_member
            tool_result = await _execute_tool(tool_name, tool_args)
            return {
                "text": f"Here are the results for your query:",
                "tool_name": tool_name,
                "tool_result": tool_result,
            }
        return {
            "text": "I can help you find warm paths, search contacts, or check relationship strength. Try asking something like 'Who do we know at Goldman Sachs?' or 'Find a path to the CIO at Barclays'.",
            "tool_name": None,
            "tool_result": None,
        }

    # LLM-powered path
    try:
        from openai import AsyncOpenAI

        client = AsyncOpenAI(api_key=api_key, base_url=base_url)

        messages = [{"role": "system", "content": SYSTEM_PROMPT}]
        for msg in request.history:
            messages.append({"role": msg.role, "content": msg.content})
        messages.append({"role": "user", "content": request.message})

        if request.source_member:
            messages[0]["content"] += (
                f"\n\nThe current user/team member is: {request.source_member}. "
                "Use this as the source_member when calling find_warm_path."
            )

        response = await client.chat.completions.create(
            model=model,
            messages=messages,
            tools=TOOL_DEFINITIONS,
            tool_choice="auto",
        )

        choice = response.choices[0]

        if choice.message.tool_calls:
            tool_call = choice.message.tool_calls[0]
            tool_name = tool_call.function.name
            tool_args = json.loads(tool_call.function.arguments)

            if tool_name == "find_warm_path" and request.source_member and "source_member" not in tool_args:
                tool_args["source_member"] = request.source_member

            tool_result = await _execute_tool(tool_name, tool_args)

            # Send tool result back to LLM for natural language summary
            messages.append(choice.message.model_dump())
            messages.append(
                {
                    "role": "tool",
                    "tool_call_id": tool_call.id,
                    "content": json.dumps(tool_result),
                }
            )

            follow_up = await client.chat.completions.create(
                model=model,
                messages=messages,
            )

            return {
                "text": follow_up.choices[0].message.content,
                "tool_name": tool_name,
                "tool_result": tool_result,
            }

        return {
            "text": choice.message.content,
            "tool_name": None,
            "tool_result": None,
        }

    except Exception as exc:
        logger.exception("LLM call failed, falling back to intent parser")
        intent = _fallback_intent(request.message)
        if intent:
            tool_name, tool_args = intent
            if tool_name == "find_warm_path" and request.source_member:
                tool_args["source_member"] = request.source_member
            tool_result = await _execute_tool(tool_name, tool_args)
            return {
                "text": f"(LLM unavailable, using fallback) Here are the results:",
                "tool_name": tool_name,
                "tool_result": tool_result,
            }
        return {
            "text": f"Sorry, I encountered an error: {exc}",
            "tool_name": None,
            "tool_result": None,
        }

import httpx

from tools._config import backend_url, api_key


async def search_by_company_or_role(
    company: str = "", role: str = ""
) -> list[dict]:
    """Search the network for contacts by company and/or role."""
    params = {}
    if company:
        params["company"] = company
    if role:
        params["role"] = role

    async with httpx.AsyncClient(timeout=30) as client:
        resp = await client.get(
            f"{backend_url}/api/graph/search",
            params=params,
            headers={"X-API-Key": api_key},
        )
        resp.raise_for_status()
        data = resp.json()
        return data.get("results", [])

