export function ChatInterface() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [sourceMember, setSourceMember] = useState("");
  const [loading, setLoading] = useState(false);
  const [showUploader, setShowUploader] = useState(false);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = async () => {
    const text = input.trim();
    if (!text || loading) return;

    const userMsg: Message = {
      id: crypto.randomUUID(),
      role: "user",
      content: text,
    };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setLoading(true);

    try {
      const resp = await fetch(`${BACKEND_URL}/api/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: text,
          history: messages.slice(-10).map((m) => ({
            role: m.role,
            content: m.content,
          })),
          source_member: sourceMember,
        }),
      });

      const data = await resp.json();
      const assistantMsg: Message = {
        id: crypto.randomUUID(),
        role: "assistant",
        content: data.text || "No response",
        tool_name: data.tool_name,
        tool_result: data.tool_result,
      };
      setMessages((prev) => [...prev, assistantMsg]);
    } catch {
      setMessages((prev) => [
        ...prev,
        {
          id: crypto.randomUUID(),
          role: "assistant",
          content: "Failed to connect to the backend. Is it running?",
        },
      ]);
    } finally {
      setLoading(false);
    }
  };

  const renderToolResult = (msg: Message) => {
    if (!msg.tool_result) return null;
    const { type, data } = msg.tool_result;

    if (type === "path" && Array.isArray(data)) {
      return <PathHighlight path={data} />;
    }
    if (type === "search" && Array.isArray(data)) {
      return <SearchResultCard results={data as Record<string, unknown>[]} />;
    }
    if (type === "score" && data) {
      return <ScoreCard data={data as Record<string, unknown>} />;
    }
    return null;
  };

  return (
    <div className="flex h-full flex-col">
      {/* Source member bar */}
      <div className="border-b border-zinc-800 bg-zinc-900/50 px-6 py-2">
        <div className="mx-auto flex max-w-3xl items-center gap-2">
          <label className="text-xs font-medium text-zinc-500">
            Acting as:
          </label>
          <input
            type="text"
            value={sourceMember}
            onChange={(e) => setSourceMember(e.target.value)}
            placeholder="Your name (e.g., Paras Mehta)"
            className="flex-1 rounded-md border border-zinc-700 bg-zinc-800 px-2 py-1 text-xs text-zinc-200 placeholder-zinc-600 outline-none focus:border-indigo-500"
          />
          <button
            onClick={() => setShowUploader(true)}
            className="rounded-md bg-zinc-800 px-3 py-1 text-xs font-medium text-zinc-300 transition-colors hover:bg-zinc-700"
          >
            Import CSV
          </button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto px-6 py-4">
        <div className="mx-auto max-w-3xl space-y-4">
          {messages.length === 0 && (
            <div className="flex flex-col items-center justify-center pt-24 text-center">
              <div className="mb-4 flex h-14 w-14 items-center justify-center rounded-2xl bg-indigo-600/20">
                <svg
                  width="28"
                  height="28"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="1.5"
                  className="text-indigo-400"
                >
                  <path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                  <path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                </svg>
              </div>
              <h2 className="mb-2 text-lg font-semibold text-zinc-200">
                Network Intelligence
              </h2>
              <p className="max-w-sm text-sm text-zinc-500">
                Ask me about your network. Try:
              </p>
              <div className="mt-3 space-y-1.5">
                {[
                  "Who do we know at Goldman Sachs?",
                  "Find a warm path to the CIO at Barclays",
                  "Show me our strongest connections at hedge funds",
                ].map((q) => (
                  <button
                    key={q}
                    onClick={() => {
                      setInput(q);
                    }}
                    className="block w-full rounded-lg border border-zinc-800 px-4 py-2 text-left text-sm text-zinc-400 transition-colors hover:border-zinc-600 hover:text-zinc-200"
                  >
                    {q}
                  </button>
                ))}
              </div>
            </div>
          )}

          {messages.map((msg) => (
            <div
              key={msg.id}
              className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}
            >
              <div
                className={`max-w-[85%] rounded-2xl px-4 py-2.5 ${
                  msg.role === "user"
                    ? "bg-indigo-600 text-white"
                    : "bg-zinc-800 text-zinc-200"
                }`}
              >
                <p className="whitespace-pre-wrap text-sm">{msg.content}</p>
                {msg.role === "assistant" && renderToolResult(msg)}
              </div>
            </div>
          ))}

          {loading && (
            <div className="flex justify-start">
              <div className="rounded-2xl bg-zinc-800 px-4 py-3">
                <div className="flex gap-1">
                  <span className="h-2 w-2 animate-bounce rounded-full bg-zinc-500" />
                  <span className="h-2 w-2 animate-bounce rounded-full bg-zinc-500 [animation-delay:0.1s]" />
                  <span className="h-2 w-2 animate-bounce rounded-full bg-zinc-500 [animation-delay:0.2s]" />
                </div>
              </div>
            </div>
          )}
          <div ref={bottomRef} />
        </div>
      </div>

      {/* Input bar */}
      <div className="border-t border-zinc-800 bg-zinc-900/80 px-6 py-3">
        <div className="mx-auto flex max-w-3xl items-end gap-2">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                sendMessage();
              }
            }}
            placeholder="Ask about your network..."
            rows={1}
            className="flex-1 resize-none rounded-xl border border-zinc-700 bg-zinc-800 px-4 py-2.5 text-sm text-zinc-100 placeholder-zinc-500 outline-none focus:border-indigo-500"
          />
          <button
            onClick={sendMessage}
            disabled={loading || !input.trim()}
            className="rounded-xl bg-indigo-600 p-2.5 text-white transition-colors hover:bg-indigo-500 disabled:opacity-40"
          >
            <svg
              width="18"
              height="18"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
            >
              <path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z" />
            </svg>
          </button>
        </div>
      </div>

      {showUploader && (
        <CSVUploader
          onClose={() => setShowUploader(false)}
          onSuccess={(result) => {
            setShowUploader(false);
            setMessages((prev) => [
              ...prev,
              {
                id: crypto.randomUUID(),
                role: "assistant",
                content: `Import complete: ${result.imported} new contacts imported, ${result.merged} merged. ${result.message}`,
              },
            ]);
          }}
        />
      )}
    </div>
  );
}

