interface GraphNode {
  id: string;
  label: string;
  company: string;
  role: string;
  is_member: boolean;
  strength: number;
}

interface GraphEdge {
  source: string;
  target: string;
  strength: number;
  source_member: string;
}

interface ScoreDetails {
  name: string;
  company: string;
  role: string;
  overall: number;
  recency: number;
  seniority: number;
  shared_connections: number;
  source_diversity: boolean;
